//! Error types specific to the high-level API.

use std::fmt;
use thiserror::Error;

/// Errors that can occur during AI operations.
#[derive(Debug, Error)]
pub enum AIError {
    /// No output was generated by the model.
    #[error("No output was generated by the model")]
    NoOutputGenerated,

    /// No speech was generated.
    #[error("No speech was generated")]
    NoSpeechGenerated,

    /// No image was generated.
    #[error("No image was generated")]
    NoImageGenerated,

    /// No video was generated (with response metadata).
    #[error("{0}")]
    NoVideoGeneratedWithResponse(#[from] NoVideoGeneratedError),

    /// No transcript was generated.
    #[error("No transcript was generated")]
    NoTranscriptGenerated,

    /// No object was generated (with detailed metadata).
    #[error("{0}")]
    NoObjectGeneratedDetailed(NoObjectGeneratedError),

    /// Invalid argument provided.
    #[error("Invalid argument: {0}")]
    InvalidArgument(String),

    /// Maximum steps exceeded.
    #[error("Maximum steps exceeded: {0} steps")]
    MaxStepsExceeded(u32),

    /// Tool execution failed.
    #[error("Tool execution failed: {0}")]
    ToolExecutionFailed(String),

    /// Schema validation failed.
    #[error("Schema validation failed: {0}")]
    SchemaValidation(String),

    /// Invalid stream part encountered.
    #[error("{0}")]
    InvalidStreamPart(#[from] InvalidStreamPartError),

    /// Invalid tool approval.
    #[error("{0}")]
    InvalidToolApproval(#[from] InvalidToolApprovalError),

    /// Invalid tool input.
    #[error("{0}")]
    InvalidToolInput(#[from] InvalidToolInputError),

    /// Missing tool results.
    #[error("{0}")]
    MissingToolResults(#[from] MissingToolResultsError),

    /// No such tool.
    #[error("{0}")]
    NoSuchTool(#[from] NoSuchToolError),

    /// Tool call not found for approval.
    #[error("{0}")]
    ToolCallNotFoundForApproval(#[from] ToolCallNotFoundForApprovalError),

    /// Tool call repair failed.
    #[error("{0}")]
    ToolCallRepair(#[from] ToolCallRepairError),

    /// Unsupported model version.
    #[error("{0}")]
    UnsupportedModelVersion(#[from] UnsupportedModelVersionError),

    /// Provider error.
    #[error("Provider error: {0}")]
    ProviderError(#[from] vercel_ai_provider::AISdkError),

    /// Operation timed out.
    #[error("Timeout: {0}")]
    Timeout(String),

    /// Invalid configuration.
    #[error("Invalid configuration: {0}")]
    InvalidConfig(String),

    /// JSON error.
    #[error("JSON error: {0}")]
    JsonError(#[from] serde_json::Error),

    /// Internal error.
    #[error("Internal error: {0}")]
    Internal(String),
}

impl AIError {
    /// Check if this is a no output generated error.
    pub fn is_no_output(&self) -> bool {
        matches!(self, Self::NoOutputGenerated)
    }

    /// Check if this is a no speech generated error.
    pub fn is_no_speech(&self) -> bool {
        matches!(self, Self::NoSpeechGenerated)
    }

    /// Check if this is a no image generated error.
    pub fn is_no_image(&self) -> bool {
        matches!(self, Self::NoImageGenerated)
    }

    /// Check if this is a no video generated error.
    pub fn is_no_video(&self) -> bool {
        matches!(self, Self::NoVideoGeneratedWithResponse(_))
    }

    /// Check if this is a no transcript generated error.
    pub fn is_no_transcript(&self) -> bool {
        matches!(self, Self::NoTranscriptGenerated)
    }

    /// Check if this is a no object generated error.
    pub fn is_no_object(&self) -> bool {
        matches!(self, Self::NoObjectGeneratedDetailed(_))
    }
}

/// Error thrown when no output is generated.
#[derive(Debug, Default, Error)]
#[error("No output generated")]
pub struct NoOutputGeneratedError {
    /// The prompt that was sent to the model.
    pub prompt: Option<String>,
    /// The model that was used.
    pub model_id: Option<String>,
}

impl NoOutputGeneratedError {
    /// Create a new no output generated error.
    pub fn new() -> Self {
        Self::default()
    }

    /// Add the prompt that was sent to the model.
    pub fn with_prompt(mut self, prompt: impl Into<String>) -> Self {
        self.prompt = Some(prompt.into());
        self
    }

    /// Add the model ID that was used.
    pub fn with_model_id(mut self, model_id: impl Into<String>) -> Self {
        self.model_id = Some(model_id.into());
        self
    }
}

/// Error thrown when an invalid argument is provided.
#[derive(Debug, Error)]
#[error("Invalid argument: {message}")]
pub struct InvalidArgumentError {
    /// The error message.
    pub message: String,
    /// The argument name.
    pub argument: Option<String>,
}

impl InvalidArgumentError {
    /// Create a new invalid argument error.
    pub fn new(message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
            argument: None,
        }
    }

    /// Add the argument name.
    pub fn with_argument(mut self, argument: impl Into<String>) -> Self {
        self.argument = Some(argument.into());
        self
    }
}

/// Error thrown when schema validation fails.
#[derive(Debug, Error)]
#[error("Schema validation failed: {message}")]
pub struct SchemaValidationError {
    /// The error message.
    pub message: String,
    /// The value that failed validation.
    pub value: Option<serde_json::Value>,
    /// The schema that was used.
    pub schema: Option<serde_json::Value>,
}

impl SchemaValidationError {
    /// Create a new schema validation error.
    pub fn new(message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
            value: None,
            schema: None,
        }
    }

    /// Add the value that failed validation.
    pub fn with_value(mut self, value: serde_json::Value) -> Self {
        self.value = Some(value);
        self
    }

    /// Add the schema that was used.
    pub fn with_schema(mut self, schema: serde_json::Value) -> Self {
        self.schema = Some(schema);
        self
    }
}

