/// Error thrown when a tool approval response references an unknown approval ID.
#[derive(Debug, Error)]
#[error(
    "Tool approval response references unknown approvalId: \"{approval_id}\". No matching tool-approval-request found in message history."
)]
pub struct InvalidToolApprovalError {
    /// The approval ID that was not found.
    pub approval_id: String,
}

impl InvalidToolApprovalError {
    /// Create a new invalid tool approval error.
    pub fn new(approval_id: impl Into<String>) -> Self {
        Self {
            approval_id: approval_id.into(),
        }
    }
}

/// Error thrown when tool input validation fails.
#[derive(Debug, Clone, Error)]
#[error("Invalid input for tool {tool_name}: {message}")]
pub struct InvalidToolInputError {
    /// The tool name.
    pub tool_name: String,
    /// The tool input that was invalid.
    pub tool_input: String,
    /// The error message.
    pub message: String,
    /// The underlying cause.
    pub cause: Option<String>,
}

impl InvalidToolInputError {
    /// Create a new invalid tool input error.
    pub fn new(tool_name: impl Into<String>, tool_input: impl Into<String>) -> Self {
        Self {
            tool_name: tool_name.into(),
            tool_input: tool_input.into(),
            message: String::new(),
            cause: None,
        }
    }

    /// Set the error message.
    pub fn with_message(mut self, message: impl Into<String>) -> Self {
        self.message = message.into();
        self
    }

    /// Set the underlying cause.
    pub fn with_cause(mut self, cause: impl Into<String>) -> Self {
        self.cause = Some(cause.into());
        self
    }
}

/// Error thrown when tool results are missing for tool calls.
#[derive(Debug, Error)]
pub struct MissingToolResultsError {
    /// The tool call IDs that are missing results.
    pub tool_call_ids: Vec<String>,
}

impl fmt::Display for MissingToolResultsError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let plural = if self.tool_call_ids.len() > 1 {
            "s"
        } else {
            ""
        };
        let verb = if self.tool_call_ids.len() > 1 {
            "are"
        } else {
            "is"
        };
        write!(
            f,
            "Tool result{} {} missing for tool call{} {}",
            plural,
            verb,
            plural,
            self.tool_call_ids.join(", ")
        )
    }
}

impl MissingToolResultsError {
    /// Create a new missing tool results error.
    pub fn new(tool_call_ids: Vec<String>) -> Self {
        Self { tool_call_ids }
    }
}

/// Error thrown when a model tries to call an unavailable tool.
#[derive(Debug, Clone, Error)]
pub struct NoSuchToolError {
    /// The tool name that was requested.
    pub tool_name: String,
    /// The available tools.
    pub available_tools: Option<Vec<String>>,
}

impl fmt::Display for NoSuchToolError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match &self.available_tools {
            Some(tools) => write!(
                f,
                "Model tried to call unavailable tool '{}'. Available tools: {}.",
                self.tool_name,
                tools.join(", ")
            ),
            None => write!(
                f,
                "Model tried to call unavailable tool '{}'. No tools are available.",
                self.tool_name
            ),
        }
    }
}

impl NoSuchToolError {
    /// Create a new no such tool error.
    pub fn new(tool_name: impl Into<String>) -> Self {
        Self {
            tool_name: tool_name.into(),
            available_tools: None,
        }
    }

    /// Set the available tools.
    pub fn with_available_tools(mut self, tools: Vec<String>) -> Self {
        self.available_tools = Some(tools);
        self
    }
}

/// Error thrown when a tool call is not found for an approval request.
#[derive(Debug, Error)]
#[error("Tool call \"{tool_call_id}\" not found for approval request \"{approval_id}\".")]
pub struct ToolCallNotFoundForApprovalError {
    /// The tool call ID.
    pub tool_call_id: String,
    /// The approval ID.
    pub approval_id: String,
}

impl ToolCallNotFoundForApprovalError {
    /// Create a new tool call not found for approval error.
    pub fn new(tool_call_id: impl Into<String>, approval_id: impl Into<String>) -> Self {
        Self {
            tool_call_id: tool_call_id.into(),
            approval_id: approval_id.into(),
        }
    }
}

/// Error thrown when tool call repair fails.
#[derive(Debug, Clone, Error)]
#[error("Error repairing tool call: {message}")]
pub struct ToolCallRepairError {
    /// The error message.
    pub message: String,
    /// The original error that triggered the repair.
    pub original_error: ToolCallRepairOriginalError,
}

/// The original error that triggered a tool call repair.
#[derive(Debug, Clone)]
pub enum ToolCallRepairOriginalError {
    /// The tool was not found.
    NoSuchTool(NoSuchToolError),
    /// The tool input was invalid.
    InvalidToolInput(InvalidToolInputError),
}

impl ToolCallRepairError {
    /// Create a new tool call repair error.
    pub fn new(message: impl Into<String>, original_error: ToolCallRepairOriginalError) -> Self {
        Self {
            message: message.into(),
            original_error,
        }
    }
}

/// Error thrown when a model with an unsupported version is used.
#[derive(Debug, Error)]
#[error(
    "Unsupported model version {version} for provider \"{provider}\" and model \"{model_id}\". AI SDK 5 only supports models that implement specification version \"v2\"."
)]
pub struct UnsupportedModelVersionError {
    /// The unsupported version.
    pub version: String,
    /// The provider name.
    pub provider: String,
    /// The model ID.
    pub model_id: String,
}

impl UnsupportedModelVersionError {
    /// Create a new unsupported model version error.
    pub fn new(
        version: impl Into<String>,
        provider: impl Into<String>,
        model_id: impl Into<String>,
    ) -> Self {
        Self {
            version: version.into(),
            provider: provider.into(),
            model_id: model_id.into(),
        }
    }
}

